const now = new Date();
const day = now.getUTCDay(); // 0=Sun, 1=Mon, ...

// Find this Monday (start of current week)
const thisMonday = new Date(Date.UTC(now.getUTCFullYear(), now.getUTCMonth(), now.getUTCDate()));
const diff = day === 0 ? 6 : day - 1;
thisMonday.setUTCDate(thisMonday.getUTCDate() - diff);

// This Sunday = thisMonday + 6
const thisSunday = new Date(thisMonday);
thisSunday.setUTCDate(thisSunday.getUTCDate() + 6);

const weekStart = thisMonday.toISOString().slice(0, 10);
const weekEnd = thisSunday.toISOString().slice(0, 10);

return [{ json: { week_start: weekStart, week_end: weekEnd } }];

