  signal_id: s.id,
  signal_type: s.signal_type,
  title: s.title,
  summary: s.summary,
  evidence_urls: s.evidence_urls || []
}));

const systemPrompt = `You are a SIGNAL FORMATTER extracting buyer language phrases from competitive intelligence signals${isPersonalized ? ` for ${companyName}` : ''}.

ABSOLUTE RULES:
1. ONLY extract phrases that appear in or are directly supported by the signals.
2. Every phrase MUST cite the source_signal_id it came from.
3. Do NOT invent buyer language, pain points, or competitive mentions not in the signals.
4. Use EXACT language from signals where possible. Minimal paraphrasing only.
5. If fewer than 5 phrases can be extracted, return fewer. Do NOT pad with invented content.

Output raw JSON only (no markdown fences):
{
  "phrases": [
    {
      "text": "string — exact or near-exact phrase from signal",
      "category": "pain_points|desired_outcomes|objections|trigger_events|evaluation_criteria|competitive_mentions",
      "persona": "string",
      "source_signal_id": "uuid — REQUIRED",
      "confidence": 0.0-1.0
    }
