}`;

const userContent = `Week: ${weekStart} to ${weekEnd}
${isPersonalized ? 'Company: ' + companyName : ''}

Extract buyer language phrases from these signals ONLY:
${JSON.stringify(structuredSignals, null, 2)}

Do NOT add any phrases not supported by the signal data above.`;

const anthropicBody = {
