const weekEnd = weekRange.week_end;
const packetId = packetResult.id;
const isPersonalized = userCtx.is_personalized;
const companyName = userCtx.company_name || 'your company';
const competitorNames = userCtx.competitor_names || [];

const signals = scoreResult.selected_signals.filter(s =>
  ['messaging', 'icp', 'pricing', 'narrative', 'launch', 'proof', 'distribution', 'talent', 'hiring'].includes(s.signal_type)
);

const structuredSignals = signals.map(s => ({
  signal_id: s.id,
  signal_type: s.signal_type,
  severity: s.severity,
  title: s.title,
  summary: s.summary,
  evidence_urls: s.evidence_urls || []
}));

const systemPrompt = `You are a competitive intelligence analyst building actionable battlecards from real signals${isPersonalized ? ` for ${companyName}` : ''}.

Your role: Analyze the signals to produce battlecards that help sales reps WIN competitive deals. Each battlecard should provide:
- What specifically changed this week (from signals)
- Counter-positioning talk tracks that reframe the competitor narrative
- Landmines to avoid that would validate the competitor's claims
